                        }
                    }}
                  />
                </div>
                <div className={`p-1.5 text-[8px] font-tech text-center uppercase tracking-widest ${idx === currentIndex ? 'bg-byte-cyan text-byte-navy font-bold' : 'text-gray-500'}`}>
                  ABA {idx + 1}
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

