    setCurrentIndex((prev) => (prev + 1) % SCREENSHOTS.length);
  };

  const prevSlide = () => {
    setCurrentIndex((prev) => (prev - 1 + SCREENSHOTS.length) % SCREENSHOTS.length);
  };

  const handleImageError = (index: number) => {
    console.warn(`Asset ${SCREENSHOTS[index].url} não carregado. Ativando Modo Simulação para o usuário.`);
    setImageErrors(prev => ({ ...prev, [index]: true }));
  };

  return (
    <section id="showcase" className="py-24 bg-byte-dark relative overflow-hidden">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-byte-purple/15 via-byte-navy to-byte-navy"></div>

      <div className="container mx-auto px-6 relative z-10">
        <div className="text-center mb-16">
          <div className="inline-flex items-center gap-2 text-byte-cyan font-tech text-xs tracking-[0.3em] mb-4">
             <Monitor size={14} /> TOUR COMPLETO PELA INTERFACE
          </div>
          <h2 className="text-4xl md:text-6xl font-tech font-bold text-white mb-6">
            DOMÍNIO <span className="text-byte-cyan">TOTAL</span>
          </h2>
          <p className="text-gray-400 max-w-2xl mx-auto text-lg leading-relaxed">
            Seja baixando vídeos em 8K ou fazendo Upscale de fotos com IA local, a interface do Byte é projetada para ser cirúrgica.
          </p>
          <div className="h-1.5 w-32 bg-gradient-to-r from-byte-purple to-byte-cyan mx-auto mt-8 rounded-full shadow-[0_0_15px_rgba(0,240,255,0.6)]"></div>
        </div>

        <div className="max-w-6xl mx-auto relative group">
          {/* Main Display Window */}
          <div className="relative aspect-video bg-[#050C16] rounded-[2.5rem] overflow-hidden shadow-[0_40px_100px_-20px_rgba(0,0,0,0.9)] border border-white/10 group-hover:border-byte-cyan/30 transition-colors duration-500">
            {/* Header Mockup */}
            <div className="absolute top-0 left-0 w-full h-10 bg-black/60 backdrop-blur-xl z-30 flex items-center px-6 border-b border-white/5">
                <div className="flex gap-2">
                   <div className="w-2.5 h-2.5 rounded-full bg-red-500/50"></div>
                   <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/50"></div>
                   <div className="w-2.5 h-2.5 rounded-full bg-green-500/50"></div>
                </div>
                <div className="mx-auto text-[10px] text-gray-500 font-tech uppercase tracking-[0.4em] opacity-60">
                  {SCREENSHOTS[currentIndex].caption.split(':')[0]} — Byte Arte
                </div>
            </div>

            <AnimatePresence mode="wait">
              {/* Se a imagem falhar, mostramos a simulação visual que criamos acima */}
              {imageErrors[currentIndex] ? (
                 <motion.div 
                    key="sim" 
                    initial={{ opacity: 0 }} 
                    animate={{ opacity: 1 }} 
                    exit={{ opacity: 0 }} 
                    className="w-full h-full"
                 >
                    <UISimulation index={currentIndex} />
                 </motion.div>
              ) : (
                <motion.img 
                  key={currentIndex}
                  initial={{ opacity: 0, scale: 0.98 }}
                  animate={{ opacity: 1, scale: 1 }}
                  exit={{ opacity: 0, scale: 1.02 }}
                  transition={{ duration: 0.5, ease: "easeOut" }}
                  src={SCREENSHOTS[currentIndex].url} 
                  alt={SCREENSHOTS[currentIndex].caption} 
                  className="w-full h-full object-contain pt-10 pb-4 px-2"
                  onError={() => handleImageError(currentIndex)}
                />
              )}
            </AnimatePresence>

            {/* Bottom Caption Overlay */}
            <div className="absolute bottom-0 left-0 w-full p-8 z-20 bg-gradient-to-t from-byte-navy via-byte-navy/80 to-transparent">
               <motion.div 
                 key={currentIndex + "-caption"}
                 initial={{ y: 20, opacity: 0 }}
                 animate={{ y: 0, opacity: 1 }}
                 className="glass-panel inline-flex items-center gap-5 px-8 py-5 rounded-2xl border-l-4 border-byte-cyan shadow-2xl animate-float max-w-[90%] md:max-w-md"
               >
                 <div className="p-3 bg-byte-cyan/10 rounded-xl border border-byte-cyan/20 shadow-[0_0_15px_rgba(0,240,255,0.1)]">
                    <Maximize2 size={24} className="text-byte-cyan" />
                 </div>
                 <div>
                    <span className="text-byte-cyan font-tech text-[10px] tracking-widest uppercase mb-1.5 block opacity-80">
                      {imageErrors[currentIndex] ? 'PROTOTIPAGEM REALTIME' : 'INTERFACE REAL'}
                    </span>
                    <h3 className="text-lg md:text-xl font-black text-white leading-tight tracking-tight">{SCREENSHOTS[currentIndex].caption}</h3>
                 </div>
               </motion.div>
            </div>

            {/* Navigation Arrows */}
            <button 
              onClick={prevSlide} 
              className="absolute left-6 top-1/2 -translate-y-1/2 z-40 p-5 rounded-full bg-byte-navy/80 border border-white/10 text-white hover:bg-byte-purple hover:border-byte-purple transition-all duration-300 backdrop-blur-xl group-hover:translate-x-2 shadow-2xl"
            >
              <ChevronLeft size={28} />
            </button>
            <button 
              onClick={nextSlide} 
              className="absolute right-6 top-1/2 -translate-y-1/2 z-40 p-5 rounded-full bg-byte-navy/80 border border-white/10 text-white hover:bg-byte-cyan hover:border-byte-cyan hover:text-byte-navy transition-all duration-300 backdrop-blur-xl group-hover:-translate-x-2 shadow-2xl"
            >
              <ChevronRight size={28} />
            </button>
          </div>

          {/* Thumbnails Navigation Grid */}
          <div className="flex flex-wrap justify-center gap-4 mt-12 max-w-4xl mx-auto">
            {SCREENSHOTS.map((screenshot, idx) => (
              <button 
                key={screenshot.id}
                onClick={() => setCurrentIndex(idx)}
                className={`group relative rounded-2xl overflow-hidden border-2 transition-all duration-500 bg-[#050C16] w-32 md:w-40 ${
                  idx === currentIndex 
                    ? 'border-byte-cyan shadow-[0_0_30px_rgba(0,240,255,0.3)] scale-110 z-10 translate-y-[-10px]' 
                    : 'border-white/5 opacity-40 hover:opacity-100 hover:border-white/20'
                }`}
              >
                <div className="aspect-video relative overflow-hidden bg-gray-900">
                  {imageErrors[idx] ? (
                    <div className="w-full h-full flex items-center justify-center bg-byte-surface">
                       <Monitor size={24} className={idx === currentIndex ? 'text-byte-cyan' : 'text-gray-700'} />
                    </div>
                  ) : (
                    <img 
                      src={screenshot.url} 
                      alt={`Aba ${idx + 1}`} 
                      className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
                    />
                  )}
                </div>
                <div className={`p-2 text-[8px] font-tech text-center uppercase tracking-widest font-black ${idx === currentIndex ? 'bg-byte-cyan text-byte-navy' : 'text-gray-500'}`}>
                  ABA {idx + 1}
                </div>
              </button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};
